# slo-burn-rate-configmap.yaml
#
# Wraps the slo-burn-rate Grafana dashboard JSON in a Kubernetes ConfigMap so
# the Grafana sidecar (grafana-sc-dashboard) auto-discovers and loads it.
#
# ── How the sidecar works ────────────────────────────────────────────────────
#
# kube-prometheus-stack ships Grafana with the sidecar container enabled by
# default.  The sidecar watches all namespaces (or a configurable set) for
# ConfigMaps that carry the label grafana_dashboard: "1" and mounts them into
# the Grafana pod at /tmp/dashboards/.  Grafana's provisioning config reads
# that directory and loads any .json files found there.
#
# No Grafana restart is required — the sidecar detects ConfigMap changes via
# the Kubernetes watch API and updates the mounted files in place.
#
# ── Deploying ────────────────────────────────────────────────────────────────
#
#   kubectl apply -f observability/prometheus/dashboards/slo-burn-rate-configmap.yaml
#
# ── Checking that the dashboard loaded ───────────────────────────────────────
#
#   kubectl logs -n monitoring -l app.kubernetes.io/name=grafana \
#     -c grafana-sc-dashboard --tail=50
#
# Look for a line containing "slo-burn-rate.json" to confirm the sidecar
# picked up the file.
#
# ── Updating the dashboard ───────────────────────────────────────────────────
#
# Edit slo-burn-rate.json, then re-apply this ConfigMap.  The sidecar detects
# the change within ~30 seconds and hot-reloads the dashboard in Grafana.
#
# To export a dashboard edited in the Grafana UI back to JSON:
#   Dashboard menu → Share → Export → Save to file
# Then replace the content of the data key below with the exported JSON.
#
apiVersion: v1
kind: ConfigMap
metadata:
  name: grafana-dashboard-slo-burn-rate
  namespace: monitoring   # <-- CHANGE THIS if Grafana runs in a different namespace
  labels:
    # The sidecar watches for this exact label.  Do not rename it.
    grafana_dashboard: "1"
    # Optional extra labels for organisational purposes only.
    app: grafana
    release: kube-prometheus-stack  # <-- CHANGE THIS to match your Helm release name
data:
  slo-burn-rate.json: |-
    {
      "__inputs": [
        {
          "name": "DS_PROMETHEUS",
          "label": "Prometheus",
