          {
            "datasource": { "type": "grafana", "uid": "-- Grafana --" },
            "enable": true,
            "hide": false,
            "iconColor": "#5794F2",
            "name": "Deployments",
            "type": "tags",
            "tags": ["deployment"],
            "builtIn": 0,
            "limit": 100,
            "showIn": 0,
            "step": "60s"
          }
        ]
      },
      "description": "Multi-window, multi-burn-rate SLO dashboard.  Uses the slo:sli_error:ratio_rate<window> recording rules produced by the availability-slo PrometheusRule template (observability/prometheus/slos/availability-slo.yaml).",
      "editable": true,
      "fiscalYearStartMonth": 0,
      "graphTooltip": 1,
      "id": null,
      "links": [],
      "panels": [
