          "datasource": { "type": "prometheus", "uid": "${datasource}" },
          "description": "Current 5-minute error rate as a percentage of total requests.  Colour thresholds reflect the burn-rate multiplier against the error budget:\n  • Green  = below 1× budget burn (on track)\n  • Yellow = 1×–6× (elevated; may page on the slow-burn alert)\n  • Orange = 6×–14× (high burn; fast-burn alert may be firing)\n  • Red    = above 14× (critical; fast-burn alert should be firing)",
          "fieldConfig": {
