          "gridPos": { "h": 5, "w": 6, "x": 0, "y": 1 },
          "id": 1,
          "options": {
            "colorMode": "background",
            "graphMode": "none",
            "justifyMode": "center",
            "orientation": "auto",
            "reduceOptions": {
              "calcs": ["lastNotNull"],
              "fields": "",
              "values": false
            },
            "textMode": "auto"
          },
          "pluginVersion": "10.0.0",
          "targets": [
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate5m{job=~\"$service\"}",
              "instant": true,
              "legendFormat": "Error rate (5m)",
              "refId": "A"
            }
          ],
          "title": "Current Error Rate (5m)",
          "type": "stat"
        },
        {
          "datasource": { "type": "prometheus", "uid": "${datasource}" },
          "description": "Percentage of the monthly error budget that has not yet been consumed.  Calculated as:\n  remaining% = 1 − (30d_burn_rate / (1 − SLO_target))\nWhere 30d_burn_rate = slo:sli_error:ratio_rate30d.\n\nA value near 100% means the service is well within budget for the month.\nA negative value means the budget has been exhausted and the SLO is already breached.",
          "fieldConfig": {
            "defaults": {
              "color": { "mode": "thresholds" },
              "decimals": 1,
              "mappings": [],
              "max": 1,
              "min": 0,
              "thresholds": {
                "mode": "absolute",
                "steps": [
                  { "color": "red",    "value": null },
                  { "color": "orange", "value": 0.2 },
                  { "color": "yellow", "value": 0.5 },
                  { "color": "green",  "value": 0.75 }
                ]
              },
              "unit": "percentunit"
            },
            "overrides": []
          },
          "gridPos": { "h": 5, "w": 6, "x": 6, "y": 1 },
          "id": 3,
          "options": {
            "minVizHeight": 75,
            "minVizWidth": 75,
            "orientation": "auto",
            "reduceOptions": {
              "calcs": ["lastNotNull"],
              "fields": "",
              "values": false
            },
            "showThresholdLabels": false,
            "showThresholdMarkers": true
          },
          "pluginVersion": "10.0.0",
          "targets": [
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "1 - (slo:sli_error:ratio_rate30d{job=~\"$service\"} / (1 - $slo_target))",
              "instant": true,
              "legendFormat": "Budget remaining",
              "refId": "A"
            }
          ],
          "title": "Error Budget Remaining (30d window)",
