        },
        {
          "collapsed": false,
          "gridPos": { "h": 1, "w": 24, "x": 0, "y": 6 },
          "id": 11,
          "title": "Error Ratio — All Windows",
          "type": "row"
        },
        {
          "datasource": { "type": "prometheus", "uid": "${datasource}" },
          "description": "Overlays the SLI error ratio across all six burn-rate windows (5m, 30m, 1h, 6h, 1d, 3d) for the selected service.  The horizontal dashed line marks the error budget (1 − SLO target).\n\nA window crossing the budget line means that window is burning faster than 1× — the service would exhaust its budget before the 30-day period ends if the rate were sustained.\n\nShorter windows react faster; longer windows smooth out transient spikes.  Alert rules fire when BOTH a fast window and a slow window simultaneously exceed their respective thresholds (multi-window burn-rate alerting).",
          "fieldConfig": {
            "defaults": {
              "color": { "mode": "palette-classic" },
              "custom": {
                "axisCenteredZero": false,
                "axisColorMode": "text",
                "axisLabel": "Error ratio",
