                "barAlignment": 0,
                "drawStyle": "line",
                "fillOpacity": 5,
                "gradientMode": "none",
                "hideFrom": { "legend": false, "tooltip": false, "viz": false },
                "lineInterpolation": "linear",
                "lineWidth": 1,
                "pointSize": 5,
                "scaleDistribution": { "type": "linear" },
                "showPoints": "never",
                "spanNulls": false,
                "stacking": { "group": "A", "mode": "none" },
                "thresholdsStyle": { "mode": "off" }
              },
              "decimals": 5,
              "mappings": [],
              "unit": "percentunit"
            },
            "overrides": [
              {
                "matcher": { "id": "byName", "options": "Error budget" },
                "properties": [
                  { "id": "color", "value": { "fixedColor": "red", "mode": "fixed" } },
                  {
                    "id": "custom.lineStyle",
                    "value": { "dash": [8, 4], "fill": "dash" }
                  },
                  { "id": "custom.lineWidth", "value": 2 }
                ]
              }
            ]
          },
          "gridPos": { "h": 9, "w": 24, "x": 0, "y": 7 },
          "id": 2,
          "options": {
            "legend": {
              "calcs": ["lastNotNull", "max"],
              "displayMode": "table",
              "placement": "bottom",
              "showLegend": true
            },
            "tooltip": { "mode": "multi", "sort": "desc" }
          },
          "pluginVersion": "10.0.0",
          "targets": [
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate5m{job=~\"$service\"}",
              "legendFormat": "5m",
              "refId": "A"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate30m{job=~\"$service\"}",
              "legendFormat": "30m",
              "refId": "B"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate1h{job=~\"$service\"}",
              "legendFormat": "1h",
              "refId": "C"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate6h{job=~\"$service\"}",
              "legendFormat": "6h",
              "refId": "D"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate1d{job=~\"$service\"}",
              "legendFormat": "1d",
              "refId": "E"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "slo:sli_error:ratio_rate3d{job=~\"$service\"}",
              "legendFormat": "3d",
              "refId": "F"
            },
            {
              "datasource": { "type": "prometheus", "uid": "${datasource}" },
              "expr": "vector(1 - $slo_target)",
              "legendFormat": "Error budget",
              "refId": "G"
            }
          ],
          "title": "Error Ratio — All Windows",
          "type": "timeseries"
        },
        {
          "collapsed": false,
          "gridPos": { "h": 1, "w": 24, "x": 0, "y": 16 },
          "id": 12,
          "title": "Burn Rate Multiplier",
          "type": "row"
        },
        {
          "datasource": { "type": "prometheus", "uid": "${datasource}" },
          "description": "Burn rate multiplier = (current error ratio) / (error budget).\n\nA value of 1× means the error budget is being consumed exactly on pace — the service would exhaust the budget in exactly 30 days.  Values above 1× mean the budget will be exhausted sooner.\n\nAlert thresholds used by the Google SRE multi-window burn-rate alerting model:\n  • 1×  — slow burn; the service will miss the SLO unless the rate drops\n  • 6×  — medium burn; triggers the slow-window alert (1h|5m pair)\n  • 14× — fast burn; triggers the fast-window alert (5m|1h pair, pages immediately)\n\nReference: https://sre.google/workbook/alerting-on-slos/#multiple_burn_rate_alerts",
          "fieldConfig": {
            "defaults": {
              "color": { "mode": "palette-classic" },
              "custom": {
                "axisCenteredZero": false,
                "axisColorMode": "text",
