                "pointSize": 5,
                "scaleDistribution": { "type": "linear" },
                "showPoints": "never",
                "spanNulls": false,
                "stacking": { "group": "A", "mode": "none" },
                "thresholdsStyle": { "mode": "off" }
              },
              "decimals": 2,
              "mappings": [],
              "unit": "short"
            },
            "overrides": [
              {
                "matcher": { "id": "byName", "options": "1× threshold" },
                "properties": [
                  { "id": "color", "value": { "fixedColor": "yellow", "mode": "fixed" } },
                  { "id": "custom.lineStyle", "value": { "dash": [8, 4], "fill": "dash" } },
                  { "id": "custom.lineWidth", "value": 1 }
                ]
              },
              {
